async function loadDashboard() {
    try {
        const [dashboard, marketShare, summary] = await Promise.all([
            API.getDashboard(selectedYear),
            API.getMarketShare(selectedYear),
            API.getSalesSummary(selectedYear)
        ]);

        const brandId = currentUser?.brand_id;
        const brandData = brandId ? summary?.find(s => s.slug === currentUser?.brand?.slug) : null;

        const content = document.getElementById('pageContent');
        content.innerHTML = `
            <div class="stats-grid">
                <div class="stat-card">
                    <div class="stat-icon" style="background:rgba(59,130,246,0.15);color:#3b82f6"><i class="fas fa-chart-line"></i></div>
                    <div class="stat-value">${formatNumber(dashboard.total_market_sales)}</div>
                    <div class="stat-label">Toplam Pazar Satışı (${selectedYear})</div>
                </div>
                <div class="stat-card">
                    <div class="stat-icon" style="background:rgba(34,197,94,0.15);color:#22c55e"><i class="fas fa-tractor"></i></div>
                    <div class="stat-value">${formatNumber(dashboard.brand_sales)}</div>
                    <div class="stat-label">${brandId ? 'Marka Satışı' : 'Toplam Satış'}</div>
                </div>
                <div class="stat-card">
                    <div class="stat-icon" style="background:rgba(245,158,11,0.15);color:#f59e0b"><i class="fas fa-map-marker-alt"></i></div>
                    <div class="stat-value">${dashboard.active_provinces}</div>
                    <div class="stat-label">Aktif İl</div>
                </div>
                <div class="stat-card">
                    <div class="stat-icon" style="background:rgba(168,85,247,0.15);color:#a855f7"><i class="fas fa-percentage"></i></div>
                    <div class="stat-value">${dashboard.market_share != null ? '%' + dashboard.market_share : '-'}</div>
                    <div class="stat-label">Pazar Payı</div>
                </div>
            </div>

            <div class="grid-2">
                <div class="card">
                    <div class="card-header"><h3>Aylık Satış Trendi</h3></div>
                    <div class="card-body"><div class="chart-container"><canvas id="monthlyChart"></canvas></div></div>
                </div>
                <div class="card">
                    <div class="card-header"><h3>Pazar Payı Dağılımı</h3></div>
                    <div class="card-body"><div class="chart-container"><canvas id="marketShareChart"></canvas></div></div>
                </div>
            </div>

            <div class="grid-2">
                <div class="card">
                    <div class="card-header"><h3>En Çok Satan İller (Top 10)</h3></div>
                    <div class="card-body"><div class="chart-container"><canvas id="topProvincesChart"></canvas></div></div>
                </div>
                <div class="card">
                    <div class="card-header"><h3>Marka Sıralaması</h3></div>
                    <div class="card-body">
                        <table class="data-table">
                            <thead><tr><th>#</th><th>Marka</th><th>Satış</th><th>Pazar Payı</th></tr></thead>
                            <tbody id="brandRankingTable"></tbody>
                        </table>
                    </div>
                </div>
            </div>
        `;

        // Monthly Trend Chart
        const months = ['Oca','Şub','Mar','Nis','May','Haz','Tem','Ağu','Eyl','Eki','Kas','Ara'];
        const trendData = dashboard.monthly_trend || [];
        charts.monthly = new Chart(document.getElementById('monthlyChart'), {
            type: 'line',
            data: {
                labels: months,
                datasets: [{
                    label: 'Satış',
                    data: months.map((_, i) => {
                        const m = trendData.find(t => t.month === i + 1);
                        return m ? parseInt(m.total) : 0;
                    }),
                    borderColor: getComputedStyle(document.documentElement).getPropertyValue('--brand-primary').trim(),
                    backgroundColor: getComputedStyle(document.documentElement).getPropertyValue('--brand-primary').trim() + '20',
                    fill: true,
                    tension: 0.4,
                    pointRadius: 4,
                    pointHoverRadius: 7,
                    borderWidth: 2
                }]
            },
            options: chartOptions('Adet')
        });

        // Market Share Pie Chart
        const topBrands = (marketShare || []).slice(0, 10);
        charts.marketShare = new Chart(document.getElementById('marketShareChart'), {
            type: 'doughnut',
            data: {
                labels: topBrands.map(b => b.brand_name),
                datasets: [{
                    data: topBrands.map(b => parseFloat(b.market_share_pct || 0)),
                    backgroundColor: topBrands.map(b => b.primary_color),
                    borderWidth: 0,
                    hoverOffset: 8
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: { position: 'right', labels: { color: '#94a3b8', padding: 12, font: { size: 11 } } },
                    tooltip: { callbacks: { label: ctx => `${ctx.label}: %${ctx.parsed}` } }
                }
            }
        });

        // Top Provinces Chart
        const topProv = dashboard.top_provinces || [];
        charts.topProvinces = new Chart(document.getElementById('topProvincesChart'), {
            type: 'bar',
            data: {
                labels: topProv.map(p => p.name),
                datasets: [{
                    label: 'Satış',
                    data: topProv.map(p => parseInt(p.total)),
                    backgroundColor: getComputedStyle(document.documentElement).getPropertyValue('--brand-primary').trim() + '80',
                    borderColor: getComputedStyle(document.documentElement).getPropertyValue('--brand-primary').trim(),
                    borderWidth: 1,
                    borderRadius: 6
                }]
            },
            options: { ...chartOptions('Adet'), indexAxis: 'y' }
        });

        // Brand Ranking Table
        const tbody = document.getElementById('brandRankingTable');
        (summary || []).forEach((b, i) => {
            const isMyBrand = b.slug === currentUser?.brand?.slug;
            tbody.innerHTML += `
                <tr style="${isMyBrand ? 'background:rgba(59,130,246,0.1)' : ''}">
                    <td><div class="rank" style="background:${b.primary_color}20;color:${b.primary_color}">${i + 1}</div></td>
                    <td style="font-weight:${isMyBrand ? '700' : '400'}">${b.brand_name}</td>
                    <td>${formatNumber(b.total_sales)}</td>
                    <td>${b.province_count} il</td>
                </tr>
            `;
        });

    } catch (err) {
        showError(err);
    }
}

let dashboardFiltersCollapsed = false;
let dashboardState = null;

function dashboardSafe(value) {
    return String(value ?? '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

function formatDashboardPercent(value, digits = 1) {
    if (value === null || value === undefined || Number.isNaN(Number(value))) return '-';
    return `%${Number(value).toLocaleString('tr-TR', {
        minimumFractionDigits: digits,
        maximumFractionDigits: digits
    })}`;
}

function formatDashboardDelta(value, digits = 1) {
    if (value === null || value === undefined || Number.isNaN(Number(value))) return 'Veri yok';
    const num = Number(value);
    const sign = num >= 0 ? '+' : '-';
    return `${sign}${formatDashboardPercent(Math.abs(num), digits)}`;
}

function getDashboardDefaultBrandId() {
    if (currentUser?.role === 'admin') {
        return String(activeBrandContext?.id || '');
    }
    return String(currentUser?.brand_id || '');
}

function ensureDashboardState() {
    if (!dashboardState) {
        dashboardState = {
            brand_id: getDashboardDefaultBrandId(),
            year: String(selectedYear || new Date().getFullYear()),
            cabin_type: '',
            drive_type: '',
            hp_range: '',
            gear_config: ''
        };
    }

    if (currentUser?.role !== 'admin') {
        dashboardState.brand_id = String(currentUser?.brand_id || '');
    }

    return dashboardState;
}

function getDashboardFilters() {
    const state = ensureDashboardState();
    return {
        brand_id: state.brand_id || '',
        year: state.year || 'all',
        cabin_type: state.cabin_type || '',
        drive_type: state.drive_type || '',
        hp_range: state.hp_range || '',
        gear_config: state.gear_config || ''
    };
}

function syncDashboardStateFromDom() {
    const state = ensureDashboardState();
    const read = (id, fallback = '') => document.getElementById(id)?.value || fallback;

    // Marka banner'dan gelir; sayfa içi selectör kaldırıldı
    state.brand_id = String(activeBrandContext?.id || currentUser?.brand_id || '');
    state.year = read('dbYearFilter', state.year || 'all');
    state.cabin_type = read('dbCabinFilter', '');
    state.drive_type = read('dbDriveFilter', '');
    state.hp_range = read('dbHpFilter', '');
    state.gear_config = read('dbGearFilter', '');

    if (state.year && state.year !== 'all' && Number.isFinite(parseInt(state.year, 10))) {
        selectedYear = parseInt(state.year, 10);
    }

    if (currentUser?.role === 'admin' && state.brand_id) {
        const selectedBrand = findBrandById(state.brand_id);
        if (selectedBrand) setActiveBrandContext(selectedBrand, { persist: true });
    }

    return state;
}

function resetDashboardFilters() {
    dashboardState = {
        brand_id: getDashboardDefaultBrandId(),
        year: String(selectedYear || new Date().getFullYear()),
        cabin_type: '',
        drive_type: '',
        hp_range: '',
        gear_config: ''
    };
    loadDashboard();
}

function onDashboardFilterChange() {
    syncDashboardStateFromDom();
    loadDashboard();
}

function toggleDashboardFilters(force) {
    dashboardFiltersCollapsed = typeof force === 'boolean' ? force : !dashboardFiltersCollapsed;
    syncDashboardFilterPanel();
}

function syncDashboardFilterPanel(summaryText = '') {
    const panel = document.getElementById('dashboardFilterPanel');
    const summary = document.getElementById('dashboardFilterSummary');
    const toggleBtn = document.querySelector('[data-dashboard-collapse]');

    if (panel) panel.classList.toggle('is-collapsed', dashboardFiltersCollapsed);
    if (summaryText && summary) summary.textContent = summaryText;
    if (toggleBtn) {
        toggleBtn.innerHTML = dashboardFiltersCollapsed
            ? '<i class="fas fa-sliders-h"></i><span>Filtreleri Goster</span>'
            : '<i class="fas fa-eye-slash"></i><span>Filtreleri Gizle</span>';
    }
}

function buildDashboardFilterSummary(data) {
    const parts = [];
    if (data?.selected_brand?.brand_name) parts.push(data.selected_brand.brand_name);
    parts.push(data?.period?.label || 'Guncel görünüm');
    if (data?.highlights?.top_category?.label) parts.push(data.highlights.top_category.label);
    if (data?.highlights?.top_drive?.label) parts.push(data.highlights.top_drive.label);
    return parts.join(' • ');
}

function renderDashboardMixPills(title, items, accentClass) {
    return `
        <div class="dbx-pill-group">
            <span class="dbx-pill-title">${dashboardSafe(title)}</span>
            <div class="dbx-pill-list">
                ${(items || []).length
                    ? items.map(item => `
                        <span class="dbx-pill ${accentClass}">
                            <strong>${dashboardSafe(item.label)}</strong>
                            <small>${formatDashboardPercent(item.share_pct, 1)}</small>
                        </span>
                    `).join('')
                    : '<span class="dbx-pill dbx-pill-muted"><strong>Veri yok</strong></span>'}
            </div>
        </div>
    `;
}

function renderDashboardTrendChart(data) {
    const el = document.getElementById('dbTrendChart');
    if (!el) return;

    const rootStyles = getComputedStyle(document.documentElement);
    const brandColor = data?.selected_brand?.primary_color || rootStyles.getPropertyValue('--brand-primary').trim() || '#3b82f6';
    const trend = data?.monthly_trend || [];
    const labels = trend.map(item => item.label);
    const baseOptions = chartOptions('Satış Adedi');
    const datasets = [];

    if (data?.trend_mode === 'focus-brand' && data?.selected_brand) {
        datasets.push({
            label: 'Toplam Pazar',
            data: trend.map(item => item.market_sales),
            borderColor: '#38bdf8',
            backgroundColor: 'rgba(56,189,248,0.10)',
            fill: false,
            tension: 0.35,
            borderWidth: 2,
            pointRadius: 3
        });
        datasets.push({
            label: data.selected_brand.brand_name,
            data: trend.map(item => item.context_sales),
            borderColor: brandColor,
            backgroundColor: `${brandColor}22`,
            fill: true,
            tension: 0.35,
            borderWidth: 3,
            pointRadius: 4
        });
        if (data.period?.target_year) {
            datasets.push({
                label: `${data.period.target_year - 1} Ayni Donem`,
                data: trend.map(item => item.prev_context_sales),
                borderColor: '#94a3b8',
                backgroundColor: 'transparent',
                fill: false,
                tension: 0.28,
                borderWidth: 2,
                pointRadius: 2,
                borderDash: [8, 6]
            });
        }
    } else {
        datasets.push({
            label: data?.period?.target_year ? `${data.period.target_year} Pazar` : 'Filtrelenmis Toplam',
            data: trend.map(item => item.market_sales),
            borderColor: brandColor,
            backgroundColor: `${brandColor}22`,
            fill: true,
            tension: 0.35,
            borderWidth: 3,
            pointRadius: 4
        });
        if (data?.period?.target_year) {
            datasets.push({
                label: `${data.period.target_year - 1} Pazar`,
                data: trend.map(item => item.prev_market_sales),
                borderColor: '#94a3b8',
                backgroundColor: 'transparent',
                fill: false,
                tension: 0.28,
                borderWidth: 2,
                pointRadius: 2,
                borderDash: [8, 6]
            });
        }
    }

    charts.dashboardTrend = new Chart(el, {
        type: 'line',
        data: { labels, datasets },
        options: {
            ...baseOptions,
            plugins: {
                ...baseOptions.plugins,
                tooltip: {
                    ...baseOptions.plugins.tooltip,
                    callbacks: {
                        label: ctx => `${ctx.dataset.label}: ${formatNumber(ctx.raw)} adet`
                    }
                }
            }
        }
    });
}

